import React, { useState } from "react";
import "./Men.css";

import k1 from "../assets/kids1.jpg";
import k2 from "../assets/kids2.jpg";
import k3 from "../assets/kids3.jpg";
import k4 from "../assets/kids4.jpg";
import k5 from "../assets/kids5.jpg";
import k6 from "../assets/kids6.jpg";
import k7 from "../assets/kids7.jpg";
import k8 from "../assets/kids8.jpg";


const products = [
  { id: 1, name: "Kids T-Shirt", price: 25, img: k1 },
  { id: 2, name: "Kids Hoodie", price: 40, img: k2 },
  { id: 3, name: "Kids Jeans", price: 35, img: k3 },
  { id: 4, name: "Kids Jacket", price: 55, img: k4 },
];

function Kids() {
  const [qty, setQty] = useState({});

  const increase = (id) =>
    setQty({ ...qty, [id]: (qty[id] || 0) + 1 });

  const decrease = (id) =>
    setQty({ ...qty, [id]: Math.max((qty[id] || 0) - 1, 0) });

  return (
    <div className="men-page">
      <h2 className="men-title">Kids Collection</h2>

      <div className="men-grid">
        {products.map((item) => (
          <div className="men-card" key={item.id}>
            <div className="men-img-box">
              <img src={item.img} alt={item.name} />
            </div>

            <div className="men-info">
              <h3>{item.name}</h3>
              <p className="price">${item.price}</p>

              <div className="qty-box">
                <button onClick={() => decrease(item.id)}>-</button>
                <span>{qty[item.id] || 0}</span>
                <button onClick={() => increase(item.id)}>+</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Kids;
